sql:
SELECT MAX(uptime) AS longest_running_time
FROM (
  SELECT uptime FROM olt_status
  UNION ALL
  SELECT uptime FROM onu_status
);

SELECT AVG(uptime) AS average_olt_uptime
FROM olt_status
WHERE status = 'online';

SELECT onu_id
FROM onu_status
WHERE status = 'online';

SELECT status, COUNT(*) AS total_onus, MAX(last_update) AS last_update_time
FROM onu_status
GROUP BY status;

SELECT COUNT(onu_id)
FROM olt_ons
WHERE status = 'active';

SELECT olt_id, MAX(uptime) AS latest_uptime
FROM olt_status
GROUP BY olt_id;

external_knowledge:
Online status refers to both the OLT and ONU being in an 'online' state; 
uptime is a measure of how long the OLT has been continuously operating; 
the ranking of ONUs is determined by their total uptime in hours.

